// 带写入间隔检查的版本
HAL_StatusTypeDef EEPROM_SafeRead(I2C_HandleTypeDef *hi2c, uint16_t addr, uint8_t *buf, uint16_t len) {
    if (HAL_GetTick() - last_write_tick < EEPROM_WRITE_TIME_MS) {
        return HAL_TIMEOUT; // 写入未完成，稍后再试
    }
    return HAL_I2C_Mem_Read(hi2c, EEPROM_ADDR, addr, I2C_MEMADD_SIZE_16BIT, buf, len, 1000);
}

#define RX_BUF_SIZE 256
static volatile uint8_t dma_rx_buf[RX_BUF_SIZE];
static uint16_t rx_write_idx = 0;

// DMA 完成中断中更新写位置
void DMA1_Channel5_IRQHandler(void) {
    if (DMA1->ISR & DMA_ISR_TCIF3) {
        DMA1->IFCR = DMA_IFCR_CTCF3;
        rx_write_idx = RX_BUF_SIZE; // 接收到了 BUF_SIZE 字节
    }
}

// 应用层读取数据（非阻塞）
int uart_read_bytes(uint8_t *out, uint16_t max_len) {
    uint16_t curr = RX_BUF_SIZE - __HAL_DMA_GET_COUNTER(&hdma_usart1_rx); // DMA 剩余计数
    if (curr == rx_write_idx) return 0; // 无新数据
    uint16_t len = (rx_write_idx > curr) ? rx_write_idx - curr : RX_BUF_SIZE - curr + rx_write_idx;
    if (len > max_len) len = max_len;
    // ... 复制数据并更新读指针
    return len;
}

typedef enum {
    STATE_IDLE,
    STATE_CONNECTING,
    STATE_WORKING,
    STATE_ERROR,
    STATE_RECONNECTING
} device_state_t;

static device_state_t current_state = STATE_IDLE;

void state_machine_handle_event(event_t event) {
    device_state_t prev = current_state;
    switch (current_state) {
        case STATE_IDLE:
            if (event == EV_START) {
                current_state = STATE_CONNECTING;
                do_connect();
            }
            break;
        case STATE_CONNECTING:
            if (event == EV_SUCCESS) current_state = STATE_WORKING;
            else if (event == EV_FAIL) current_state = STATE_ERROR;
            break;
        case STATE_WORKING:
            if (event == EV_TIMEOUT) current_state = STATE_RECONNECTING;
            else if (event == EV_STOP) current_state = STATE_IDLE;
            break;
        case STATE_ERROR:
        case STATE_RECONNECTING:
            if (event == EV_RESET || event == EV_TIMEOUT_EXPIRED) current_state = STATE_IDLE;
            break;
    }
    if (prev != current_state) {
        on_state_exit(prev);
        on_state_enter(current_state);
    }
}
